import * as td from 'typedoc';
import { NavigationItemEvent } from 'typedoc-plugin-navigation-hooks';

const CUSTOM_TAG_NAME = "navigationTitle";

function defineOptions(app) {
  app.on(td.Application.EVENT_BOOTSTRAP_END, () => {
    app.options.setValue("blockTags", [
      .../* @__PURE__ */ new Set([
        ...app.options.getValue("blockTags"),
        `@${CUSTOM_TAG_NAME}`
      ])
    ]);
  });
}

function detectCustomTag(reflection, context) {
  const comment = reflection.comment;
  return comment?.getTag(`@${CUSTOM_TAG_NAME}`);
}
function removeCustomTag(reflection, context) {
  const comment = reflection.comment;
  if (!comment) return;
  comment.removeTags(`@${CUSTOM_TAG_NAME}`);
}
function parseCustomTag(customTag, context) {
  const { logger } = context;
  const navigationTitle = customTag.content.map((part) => part.text).join("").trim();
  if (!navigationTitle.length) {
    logger.error(`Navigation title is empty. Please provide a string as title.`);
  }
  return navigationTitle;
}
function augmentReflection(reflection, navigationTitle) {
  Object.defineProperty(reflection, "_navigationTitle", {
    value: navigationTitle
  });
  return reflection;
}
function updateNavElementTitle(item, reflection) {
  if (item.text) item.text = reflection._navigationTitle;
  if (item.title) item.title = reflection._navigationTitle;
  return item;
}

function load(app) {
  defineOptions(app);
  app.converter.on(
    td.Converter.EVENT_RESOLVE,
    (context, reflection) => {
      const customTag = detectCustomTag(reflection);
      if (customTag) {
        const navigationTitle = parseCustomTag(customTag, context);
        augmentReflection(reflection.isSignature() ? reflection.parent : reflection, navigationTitle);
        removeCustomTag(reflection);
      }
    }
  );
  app.renderer.on(NavigationItemEvent.RESOLVE, ({ item, reflection }) => {
    if (reflection?._navigationTitle) {
      updateNavElementTitle(item, reflection);
    }
  });
}

export { load as default, load };
